mapper.select:
SELECT m.member_id AS memberId, m.login_id AS loginId, m2.nickname AS nickname, TO_CHAR(rv.check_out_date, 'YYYY-MM') AS settlementMonth, COUNT(DISTINCT p.partner_id) AS placeCount,
/* 총 결제액 */ NVL(SUM(o.real_total_amount), 0) AS totalGmv,
/* 수수료 */ NVL(SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)), 0) AS totalCommission,
/* 쿠폰 파트너 부담 */ NVL(SUM(cu.partner_discount_amount), 0) AS totalCouponPartner,
/* 최종 지급액 */ NVL(SUM(o.real_total_amount) - SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)) - SUM(NVL(cu.partner_discount_amount, 0)), 0) AS totalNetPayout,
/* * 정산 상태 판단 * - 소속 파트너 전체 done → 'done' * - 일부만 done → 'partial' * - 하나도 done 아님 → 'wait' * ps LEFT JOIN이므로 partner_id별 done 여부를 서브쿼리로 분리해서 * row 뻥튀기 없이 COUNT */ CASE WHEN COUNT(DISTINCT p.partner_id) = COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END) THEN 'done' WHEN COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END) > 0 THEN 'partial' ELSE 'wait' END AS settlementStatus,
COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END) AS approvedPlaceCount,
MAX(p.commission_rate) AS commissionRate,
SUM(CASE WHEN rv.check_out_date < TRUNC(SYSDATE) THEN 1 ELSE 0 END) AS checkedOutCount, COUNT(rv.reservation_id) AS totalReservationCount
FROM partner p JOIN member1 m ON m.member_id = p.member_id JOIN member2 m2 ON m2.member_id = m.member_id JOIN place pl ON pl.partner_id = p.partner_id JOIN room r ON r.place_id = pl.place_id JOIN reservation rv ON rv.room_id = r.room_id JOIN order_detail od ON od.reservation_id = rv.reservation_id JOIN orders o ON o.order_id = od.order_id LEFT JOIN partner_settlement ps ON ps.partner_id = p.partner_id AND ps.settlement_month = TO_CHAR(rv.check_out_date, 'YYYY-MM') LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'CANCELED' WHERE 1=1 AND o.status != 'CANCELED'
AND TO_CHAR(rv.check_out_date, 'YYYY-MM') = #{settlementMonth}
AND (m.login_id LIKE '%' || #{keyword} || '%' OR m2.nickname LIKE '%' || #{keyword} || '%')
/* member_id 기준으로 GROUP BY → 한 멤버 1행 */ GROUP BY m.member_id, m.login_id, m2.nickname, TO_CHAR(rv.check_out_date, 'YYYY-MM')
HAVING
COUNT(DISTINCT p.partner_id) = COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END)
COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END) > 0 AND COUNT(DISTINCT p.partner_id) > COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END)
COUNT(DISTINCT CASE WHEN ps.status = 'done' THEN p.partner_id END) = 0
ORDER BY settlementMonth DESC, totalGmv DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT p.partner_id AS partnerId, m.login_id AS loginId, m2.nickname AS nickname, TO_CHAR(rv.check_out_date, 'YYYY-MM') AS settlementMonth, pl.place_id AS placeId, pl.place_name AS placeName, pl.category AS placeType, p.commission_rate AS commissionRate,
NVL(SUM(o.real_total_amount), 0) AS totalGmv, NVL(SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)), 0) AS totalCommission, NVL(SUM(cu.partner_discount_amount), 0) AS totalCouponPartner, NVL(SUM(cu.platform_discount_amount), 0) AS totalCouponPlatform, NVL(SUM(o.real_total_amount) - SUM(ROUND(o.real_total_amount * p.commission_rate / 100, 0)) - SUM(NVL(cu.partner_discount_amount, 0)), 0) AS totalNetPayout,
COUNT(DISTINCT o.order_id) AS orderCount,
/* ps.status 직접 사용 — partner:place = 1:1이므로 집계 불필요 */ NVL(ps.status, 'wait') AS settlementStatus, ps.partner_settlement_id AS settlementId
FROM partner p JOIN member1 m ON m.member_id = p.member_id JOIN member2 m2 ON m2.member_id = m.member_id JOIN place pl ON pl.partner_id = p.partner_id JOIN room r ON r.place_id = pl.place_id JOIN reservation rv ON rv.room_id = r.room_id JOIN order_detail od ON od.reservation_id = rv.reservation_id JOIN orders o ON o.order_id = od.order_id LEFT JOIN partner_settlement ps ON ps.partner_id = p.partner_id AND ps.settlement_month = TO_CHAR(rv.check_out_date, 'YYYY-MM') LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'CANCELED'
/* member_id로 소속 파트너 전체 조회 */ WHERE m.member_id = #{memberId} AND o.status != 'CANCELED'
AND TO_CHAR(rv.check_out_date, 'YYYY-MM') = #{settlementMonth}
GROUP BY p.partner_id, m.login_id, m2.nickname, TO_CHAR(rv.check_out_date, 'YYYY-MM'), pl.place_id, pl.place_name, pl.category, p.commission_rate, ps.status, ps.partner_settlement_id ORDER BY pl.place_id

SELECT p.partner_id
FROM partner p
WHERE p.member_id = #{memberId}

SELECT o.order_id, od.reservation_id, o.order_date, guest2.nickname AS guestNickname, o.total_amount, o.coupon_discount, o.point_discount, o.real_total_amount, NVL(cu.platform_discount_amount, 0) AS couponPlatformAmt, NVL(cu.partner_discount_amount, 0) AS couponPartnerAmt, p.commission_rate, ROUND(o.real_total_amount * p.commission_rate / 100) AS commissionAmount, (o.real_total_amount - ROUND(o.real_total_amount * p.commission_rate / 100) - NVL(cu.partner_discount_amount, 0)) AS partnerPayout, pay.status AS paymentStatus, o.status AS orderStatus FROM partner p JOIN place pl ON pl.partner_id = p.partner_id JOIN room r ON r.place_id = pl.place_id JOIN reservation rv ON rv.room_id = r.room_id JOIN order_detail od ON od.reservation_id = rv.reservation_id JOIN orders o ON o.order_id = od.order_id JOIN member1 guest ON guest.member_id = o.member_id JOIN member2 guest2 ON guest2.member_id = guest.member_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'CANCELED' LEFT JOIN payment pay ON pay.order_id = o.order_id WHERE p.member_id = #{memberId} AND o.status != 'CANCELED'
AND TO_CHAR(rv.check_out_date, 'YYYY-MM') = #{settlementMonth}
ORDER BY pl.place_id, o.order_date DESC

SELECT o.order_id, od.reservation_id, o.order_date, guest2.nickname AS guestNickname, o.total_amount, o.coupon_discount, o.point_discount, o.real_total_amount, NVL(cu.platform_discount_amount, 0) AS couponPlatformAmt, NVL(cu.partner_discount_amount, 0) AS couponPartnerAmt, p.commission_rate, ROUND(o.real_total_amount * p.commission_rate / 100) AS commissionAmount, (o.real_total_amount - ROUND(o.real_total_amount * p.commission_rate / 100) - NVL(cu.partner_discount_amount, 0)) AS partnerPayout, pay.status AS paymentStatus, o.status AS orderStatus FROM orders o JOIN order_detail od ON od.order_id = o.order_id JOIN reservation rv ON rv.reservation_id = od.reservation_id JOIN room r ON r.room_id = rv.room_id JOIN place pl ON pl.place_id = r.place_id JOIN partner p ON p.partner_id = pl.partner_id JOIN member1 guest ON guest.member_id = o.member_id JOIN member2 guest2 ON guest2.member_id = guest.member_id LEFT JOIN coupon_usage cu ON cu.order_id = o.order_id AND cu.partner_id = p.partner_id AND cu.place_id = pl.place_id AND cu.status != 'CANCELED' LEFT JOIN payment pay ON pay.order_id = o.order_id WHERE p.partner_id = #{partnerId} AND o.status != 'CANCELED'
AND TO_CHAR(rv.check_out_date, 'YYYY-MM') = #{settlementMonth}
ORDER BY o.order_date DESC
